mapper.select:
/*WorkMgmtMapper.dupChkItem*/
SELECT COUNT(1)
FROM NMCP_WORK_ITEM@DL_MCP
WHERE ITEM_NM = #{itemNm}
  AND STATUS = 'A'

    AND ITEM_ID != #{itemId}

mapper.insert:
/* WorkMgmtMapper.insertWorkItem */
INSERT INTO NMCP_WORK_ITEM@DL_MCP
(
    ITEM_ID
    ,ITEM_NM
    ,STATUS
    ,REQUEST_YN
    ,CRET_ID
    ,CRET_DT
 )
VALUES
(
    TO_CHAR(SYSDATE,'YYYYMMDD') || LPAD(SQ_WORK_ITEM.NEXTVAL@DL_MCP, 4, '0')
    ,#{itemNm}
    ,'A'
    ,#{requestYn}
    ,#{sessionUserId}
    ,SYSDATE
)

mapper.update:
/* WorkMgmtMapper.updateWorkItem */
UPDATE NMCP_WORK_ITEM@DL_MCP
SET ITEM_NM = #{itemNm}
    ,REQUEST_YN = #{requestYn}
    ,AMD_ID = #{sessionUserId}
    ,AMD_DT = SYSDATE
WHERE ITEM_ID = #{itemId}

/* WorkMgmtMapper.updateWorkItemEnd */
UPDATE NMCP_WORK_ITEM@DL_MCP
SET STATUS = 'D'
  ,DEL_DT = SYSDATE
  ,AMD_ID = #{sessionUserId}
  ,AMD_DT = SYSDATE
WHERE ITEM_ID = #{itemId}

