mapper.select:
/*WorkMgmtMapper.dupChkRqstr*/
SELECT COUNT(1)
FROM NMCP_WORK_RQSTR@DL_MCP
WHERE RQSTR_NM = #{rqstrNm}
  AND STATUS = 'A'

    AND RQSTR_ID != #{rqstrId}

mapper.update:
/* WorkMgmtMapper.updateWorkRqstr */
UPDATE NMCP_WORK_RQSTR@DL_MCP
SET RQSTR_NM = #{rqstrNm}
    ,AMD_ID = #{sessionUserId}
    ,AMD_DT = SYSDATE
WHERE RQSTR_ID = #{rqstrId}

mapper.select:
/* WorkMgmtMapper.checkWorkTmplInUse */ SELECT A.WORK_TMPL_ID ,A.WORK_TMPL_NM FROM NMCP_WORK_TMPL@DL_MCP A ,NMCP_WORK_TMPL_ITEM@DL_MCP B ,NMCP_WORK_TMPL_OWNER@DL_MCP C ,NMCP_WORK_TMPL_RQSTR@DL_MCP D WHERE A.WORK_TMPL_ID = B.WORK_TMPL_ID AND A.WORK_TMPL_ID = C.WORK_TMPL_ID AND A.WORK_TMPL_ID = D.WORK_TMPL_ID AND A.END_DT > SYSDATE
AND B.ITEM_ID = #{itemId}
AND C.OWNER_ID = #{ownerId}
AND D.RQSTR_ID = #{rqstrId}
AND ROWNUM = 1

mapper.update:
/* WorkMgmtMapper.updateWorkRqstrEnd */
UPDATE NMCP_WORK_RQSTR@DL_MCP
SET STATUS = 'D'
  ,DEL_DT = SYSDATE
  ,AMD_ID = #{sessionUserId}
  ,AMD_DT = SYSDATE
WHERE RQSTR_ID = #{rqstrId}

mapper.insert:
/* WorkMgmtMapper.insertWorkTmpl */

    SELECT TO_CHAR(SYSDATE,'YYYYMMDD') || LPAD(SQ_WORK_TMPL.NEXTVAL@DL_MCP, 4, '0') AS WORK_TMPL_ID
    FROM DUAL


INSERT INTO NMCP_WORK_TMPL@DL_MCP
(
    WORK_TMPL_ID
    ,WORK_ID
    ,WORK_TMPL_NM
    ,USE_YN
    ,START_DT
    ,END_DT
    ,CRET_ID
    ,CRET_DT
)
VALUES
(
    #{workTmplId}
    ,#{workId}
    ,#{workTmplNm}
    ,#{useYn}
    ,SYSDATE
    ,TO_DATE('9999-12-31 00:00:00', 'YYYY-MM-DD HH24:MI:SS')
    ,#{sessionUserId}
    ,SYSDATE
)

