mapper.select:
/* WorkMgmtMapper.getWorkTmplEndDt */
SELECT TO_CHAR(END_DT, 'YYYYMMDDHH24MISS') AS END_DT
FROM NMCP_WORK_TMPL@DL_MCP
WHERE WORK_TMPL_ID = #{workTmplId}

/* WorkMgmtMapper.getWorkTmplItemList */
SELECT ITEM_ID
FROM NMCP_WORK_TMPL_ITEM@DL_MCP
WHERE WORK_TMPL_ID = #{workTmplId}

/* WorkMgmtMapper.getWorkTmplOwnerList */
SELECT OWNER_ID
FROM NMCP_WORK_TMPL_OWNER@DL_MCP
WHERE WORK_TMPL_ID = #{workTmplId}

/* WorkMgmtMapper.getWorkTmplRqstrList */
SELECT RQSTR_ID
FROM NMCP_WORK_TMPL_RQSTR@DL_MCP
WHERE WORK_TMPL_ID = #{workTmplId}

/* WorkMgmtMapper.getWorkTmplSmsList */
SELECT SMS_TEMPLATE_ID
FROM NMCP_WORK_TMPL_SMS@DL_MCP
WHERE WORK_TMPL_ID = #{workTmplId}

mapper.update:
/* WorkMgmtMapper.updateWorkTmplEnd */
UPDATE NMCP_WORK_TMPL@DL_MCP
SET END_DT = SYSDATE
    ,USE_YN = 'N'
    ,AMD_ID = #{sessionUserId}
    ,AMD_DT = SYSDATE
WHERE WORK_TMPL_ID = #{workTmplId}

/* WorkMgmtMapper.updateWorkTmpl */
UPDATE NMCP_WORK_TMPL@DL_MCP
SET WORK_ID = #{workId}
    ,WORK_TMPL_NM = #{workTmplNm}
    ,USE_YN = #{useYn}
    ,AMD_ID = #{sessionUserId}
    ,AMD_DT = SYSDATE
WHERE WORK_TMPL_ID = #{workTmplId}
